public int minTimeToType(String word) {
    int time = 0, prev = 0;
    for (char c : word.toCharArray()) {
        int pos = c - 'a';
        time += Math.min(Math.abs(pos - prev), 26 - Math.abs(pos - prev)) + 1;
        prev = pos;
    }
    return time;
}
```


